class Solution:
    def checkPalindromeFormation(self, a: str, b: str) -> bool:
        n = len(a)
        def is_pal(s):
            return s == s[::-1]
        for i in range(n + 1):
            if is_pal(a[:i] + b[i:]) or is_pal(b[:i] + a[i:]):
                return True
        return False

