var checkPalindromeFormation = function(a, b) {
    const isPal = (s, i, j) => {
        while (i < j) {
            if (s[i] !== s[j]) return false;
            i++;
            j--;
        }
        return true;
    };
    const check = (x, y) => {
        let i = 0, j = x.length - 1;
        while (i < j && x[i] === y[j]) {
            i++;
            j--;
        }
        return isPal(x, i, j) || isPal(y, i, j);
    };
    return check(a, b) || check(b, a);
};
